external_knowledge:
- 'Top performers' refers to the sales channels with the highest total order values;
- The total order value is calculated by summing the values of all orders associated with each sales channel;
- The ranking is based on the sum of the total order values, with the highest sum receiving the rank of 1.

sql:
SELECT sales_channel_name, COUNT(sales_channel_id) AS num_channels
FROM sales_channels
GROUP BY sales_channel_name;

SELECT sales_channel_name, description
FROM sales_channels
ORDER BY sales_channel_name ASC;

SELECT sales_channel_name, description
FROM sales_channels
WHERE sales_channel_id > 1;

SELECT sales_channel_name
FROM sales_channels
WHERE sales_channel_id = 1;

